import React from "react";

export default function ThreeCards(): JSX.Element {
  const cards = [
    { id: 1, title: "Mountain Escape", img: "https://picsum.photos/id/1018/600/400", alt: "mountain landscape" },
    { id: 2, title: "City Lights", img: "https://picsum.photos/id/1015/600/400", alt: "city skyline at night" },
    { id: 3, title: "Forest Path", img: "https://picsum.photos/id/1011/600/400", alt: "forest path with trees" },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {cards.map((card) => (
        <article key={card.id} className="rounded-2xl shadow-lg overflow-hidden bg-white flex flex-col">
          <img src={card.img} alt={card.alt} className="w-full h-44 object-cover sm:h-56 lg:h-48" loading="lazy" />

          <div className="p-4 flex-1 flex flex-col justify-between">
            <div>
              <h3 className="text-lg font-medium">{card.title}</h3>
              <p className="text-sm text-gray-500 mt-2">A short description goes here.</p>
            </div>

            <div className="mt-4">
              <button
                type="button"
                aria-label={`View ${card.title}`}
                className="w-full inline-flex items-center justify-center gap-2 px-4 py-2 rounded-xl border border-transparent focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-indigo-500 transition-shadow hover:shadow-md bg-indigo-600 text-white font-semibold"
              >
                View
              </button>
            </div>
          </div>
        </article>
      ))}
    </div>
  );
}
